import { ActionIcon, Card, CopyButton, Input, Pill, Select, Textarea } from "@mantine/core";
import { computed, effect, signal, Signal } from "@preact/signals";
import { Copy, Maximize, Minimize, Pencil, PencilOff, PlusCircle, Trash2 } from "lucide-react";
import { TargetedEvent } from "preact/compat";
import randomColor from "randomcolor";
import { flushSync } from "react-dom";
import toast from "react-hot-toast";
import { ApplyDocument, ApplyDocumentType, DOCUMENT_TYPES } from "../../Common/CommonModel";
import { globalState } from "../../context/GlobalState";
import { Horizontal, Overlap, Vertical } from "../../utils/ComponentToolbox";
import { SearchableMultiSelect } from "../input/SearchableMultiSelect";

const documentWidth = computed(() => `calc(${100 / globalState.layout.columnCount.value}% - ${16}px)`);

const tagList = computed(() =>
	Array.from(new Set([...DOCUMENT_TYPES, ...globalState.documentList.value.flatMap((d) => d.value.tagList)]))
);
effect(() => {
	// add to filter list all tags that are not in the filter list
	const filterList = globalState.filterList.value;
	const newTags = tagList.value.filter((t) => !filterList.some((f) => f.value.value === t));
	if (newTags.length > 0)
		globalState.filterList.value = [...filterList, ...newTags.map((t) => signal({ value: t, enabled: false }))];

	// remove from filter list all tags that are not in the tag list
	const deletedTags = filterList.filter((f) => !tagList.value.includes(f.value.value));
	if (deletedTags.length > 0) globalState.filterList.value = filterList.filter((f) => tagList.value.includes(f.value.value));
});
effect(() => {
	// add to tag color object all tags that are not in the tag color object
	const tagColorObj = globalState.tagColorObj.value;
	const newTags = tagList.value.filter((t) => !Object.keys(tagColorObj).includes(t));
	if (newTags.length > 0)
		globalState.tagColorObj.value = { ...tagColorObj, ...Object.fromEntries(newTags.map((t) => [t, randomColor()])) };

	// remove from tag color object all tags that are not in the tag list
	const deletedTags = Object.keys(tagColorObj).filter((t) => !tagList.value.includes(t));
	if (deletedTags.length > 0)
		globalState.tagColorObj.value = Object.fromEntries(Object.entries(tagColorObj).filter(([t]) => tagList.value.includes(t)));
});

const addDocument = () =>
	document.startViewTransition(() =>
		flushSync(
			() =>
				(globalState.documentList.value = [
					signal({
						type: "text",
						tagList: [],
						content: "",
						editing: true,
						viewTransitionName: `card-${globalState.viewTransitionNameIndex.value++}`,
					}),
					...globalState.documentList.value,
				])
		)
	);

const onChangeDocumentTypeFn = (document: Signal<ApplyDocument>) => (value: string | null) =>
	value && (document.value = { ...document.value, type: value as ApplyDocumentType });

const deleteDocumentFn = (index: number) => () =>
	document.startViewTransition(() =>
		flushSync(() => (globalState.documentList.value = globalState.documentList.value.filter((_, i) => i !== index)))
	);

const onChangeDocumentEditingFn = (document: Signal<ApplyDocument>) => () =>
	(document.value = { ...document.value, editing: !document.value.editing });

const toggleFullScreenViewTransitionNameFn = (d: Signal<ApplyDocument>) => () =>
	document.startViewTransition(() =>
		flushSync(
			() =>
				(globalState.fullScreenViewTransitionName.value =
					globalState.fullScreenViewTransitionName.value === d.value.viewTransitionName ? "" : d.value.viewTransitionName)
		)
	);

const onChangeDocumentTagListFn = (document: Signal<ApplyDocument>) => (value: string[]) =>
	(document.value = { ...document.value, tagList: value });

const onChangeDocumentContentFn = (document: Signal<ApplyDocument>) => (ev: TargetedEvent<HTMLTextAreaElement>) =>
	(document.value = { ...document.value, content: ev.currentTarget.value });

const draggedTag = signal<string | null>(null);

const onDropTagFn = (i: number, j: number, d: Signal<ApplyDocument>) => () => {
	if (!draggedTag.value) return;
	if (i === 0 && j === 0) {
		addDocument();
		const newDocument = globalState.documentList.value[globalState.documentList.value.length - 1];
		newDocument.value = { ...newDocument.value, tagList: [draggedTag.value] };
		return;
	}
	if (d.value.tagList.includes(draggedTag.value)) return;
	d.value = { ...d.value, tagList: [...d.value.tagList, draggedTag.value] };
};

const isDocFullScreen = (d: Signal<ApplyDocument>) =>
	d.value.viewTransitionName === globalState.fullScreenViewTransitionName.value;

export const DocumentCard = ({ d, i, j }: { d: Signal<ApplyDocument>; i: number; j: number }) => (
	<Card
		style={{
			width: isDocFullScreen(d) ? "100%" : documentWidth.value,
			height: isDocFullScreen(d) ? "100%" : globalState.layout.rowHeight.value,
			overflow: "auto",
			viewTransitionName: d.value.viewTransitionName,
			position: isDocFullScreen(d) ? "absolute" : undefined,
			zIndex: isDocFullScreen(d) ? 500 : undefined,
			top: 0,
		}}
		padding="xs"
		onDragOver={(ev) => ev.preventDefault()}
		onDrop={onDropTagFn(i, j, d)}
	>
		{i === 0 && j === 0 ? (
			<ActionIcon style={{ width: "60%", height: "60%", margin: "auto" }} variant="transparent" size="lg" onClick={addDocument}>
				<PlusCircle width={"100%"} height={"100%"} />
			</ActionIcon>
		) : (
			<Vertical gap={3}>
				<Horizontal justifyContent="space-between">
					{d.value.editing ? (
						<Select
							label="Type"
							data={DOCUMENT_TYPES}
							value={d.value.type}
							readOnly={!d.value.editing}
							onChange={onChangeDocumentTypeFn(d)}
						/>
					) : (
						<Horizontal gap={6}>
							<Input.Label style={{ paddingBottom: 5 }}>Type</Input.Label>
							<Pill c={globalState.tagColorObj.value[d.value.type]}>{d.value.type}</Pill>
						</Horizontal>
					)}
					<Horizontal gap={6}>
						<ActionIcon
							variant="transparent"
							size="sm"
							c="red"
							onClick={deleteDocumentFn(i * globalState.layout.columnCount.value + j - 1)}
						>
							<Trash2 />
						</ActionIcon>
						<div />
						<ActionIcon variant="transparent" size="sm" onClick={toggleFullScreenViewTransitionNameFn(d)}>
							{isDocFullScreen(d) ? <Minimize /> : <Maximize />}
						</ActionIcon>
						<ActionIcon variant="transparent" size="sm" onClick={onChangeDocumentEditingFn(d)}>
							{d.value.editing ? <PencilOff /> : <Pencil />}
						</ActionIcon>
					</Horizontal>
				</Horizontal>
				{d.value.editing ? (
					<SearchableMultiSelect
						label="Tags"
						data={tagList.value}
						value={d.value.tagList}
						onChange={onChangeDocumentTagListFn(d)}
					/>
				) : (
					<Horizontal gap={6}>
						<Input.Label style={{ paddingBottom: 5 }}>Tags</Input.Label>
						{d.value.tagList.map((tag) => (
							<Pill key={tag} c={globalState.tagColorObj.value[tag]}>
								{tag}
							</Pill>
						))}
					</Horizontal>
				)}
				<Overlap>
					<Textarea
						label={`Content${d.value.editing ? "" : " (read only)"}`}
						value={d.value.content}
						onChange={onChangeDocumentContentFn(d)}
						readOnly={!d.value.editing}
						autosize
					/>
					<Horizontal justifyContent="flex-end">
						<CopyButton value={d.value.content}>
							{({ copied, copy }) => (
								<ActionIcon
									color={copied ? "teal" : "blue"}
									onClick={() => (copy(), toast.success("copied"))}
									style={{ right: 5, top: 43 }}
								>
									<Copy />
								</ActionIcon>
							)}
						</CopyButton>
					</Horizontal>
				</Overlap>
			</Vertical>
		)}
	</Card>
);
