import { MultiSelect, MultiSelectProps } from "@mantine/core";
import { useComputed, useSignal } from "@preact/signals";
import { ForwardedRef, forwardRef, PropsWithoutRef } from "react";

export const SearchableMultiSelect = forwardRef(function SearchableMultiSelect(
	props: PropsWithoutRef<MultiSelectProps> & { data: string[] },
	ref: ForwardedRef<HTMLInputElement>
) {
	const searchValue = useSignal("");
	const comptedData = useComputed(() => Array.from(new Set([...props.data, searchValue.value])));
	return (
		<MultiSelect
			ref={ref}
			searchable
			{...props}
			data={comptedData.value}
			searchValue={searchValue.value}
			onSearchChange={(value) => (searchValue.value = value)}
		/>
	);
});
